{
  "family": "Fries-, Photo-Fries, and Anionic Ortho-Fries Rearrangement",
  "candidate": {
    "substrate_smiles": [
      "CC(=O)Oc1ccccc1"
    ],
    "product_smiles": [
      "CC(=O)c1ccccc1O"
    ],
    "optional_reagent_smiles": [
      "Cl[Al](Cl)Cl"
    ],
    "rationale": "This reaction shows the classic Lewis acid-catalyzed Fries rearrangement of phenyl acetate to 2-hydroxyacetophenone. It is the simplest and most common textbook example, clearly illustrating the migration of an acyl group from a phenolic oxygen to an ortho position on the aromatic ring. The use of phenyl acetate as the substrate and aluminum chloride as the catalyst is canonical.",
    "collision_avoidance_note": "This example uses the simplest possible aromatic system (phenyl) and acyl group (acetyl) to avoid overlap with more complex named reactions involving substituted arenes or functional groups. It avoids motifs common in other rearrangements (e.g., Claisen, which involves allyl groups) or electrophilic aromatic substitutions (e.g., Friedel-Crafts acylation, which starts with a free phenol and an acylating agent). The intramolecular nature of the rearrangement is key to its specificity."
  }
}
